import{j as t,c as e,b as a,ah as i}from"./chunks/framework.Br27zpCu.js";const g=JSON.parse('{"title":"Common Mistakes","description":"","frontmatter":{},"headers":[],"relativePath":"bagisto-native/native-integration/android/base-url-configuration/common-mistakes.md","filePath":"bagisto-native/native-integration/android/base-url-configuration/common-mistakes.md","lastUpdated":1773897321000}'),n={name:"bagisto-native/native-integration/android/base-url-configuration/common-mistakes.md"};function r(s,o,l,d,c,m){return a(),e("div",null,[...o[0]||(o[0]=[i('<h1 id="common-mistakes" tabindex="-1">Common Mistakes <a class="header-anchor" href="#common-mistakes" aria-label="Permalink to &quot;Common Mistakes&quot;">​</a></h1><p>Avoiding these common pitfalls will save you time during the setup of your Android Native App.</p><h2 id="_1-incorrect-url-format" tabindex="-1">1. Incorrect URL Format <a class="header-anchor" href="#_1-incorrect-url-format" aria-label="Permalink to &quot;1. Incorrect URL Format&quot;">​</a></h2><p>The Base URL must be a valid URL string including the protocol.</p><ul><li><strong>Wrong</strong>: <code>192.168.1.10:3000</code></li><li><strong>Right</strong>: <code>http://192.168.1.10:3000/</code></li></ul><h2 id="_2-http-in-production" tabindex="-1">2. HTTP in Production <a class="header-anchor" href="#_2-http-in-production" aria-label="Permalink to &quot;2. HTTP in Production&quot;">​</a></h2><p>Forgetting that Android blocks HTTP by default on Android 9+.</p><ul><li><strong>Issue</strong>: App fails to load <code>http</code> content.</li><li><strong>Solution</strong>: Use <code>https</code> for production, or add <code>android:usesCleartextTraffic=&quot;true&quot;</code> in <code>AndroidManifest.xml</code> for development.</li></ul><h2 id="_3-network-isolation" tabindex="-1">3. Network Isolation <a class="header-anchor" href="#_3-network-isolation" aria-label="Permalink to &quot;3. Network Isolation&quot;">​</a></h2><p>The Android emulator is on a different network than your development machine.</p><ul><li><strong>Issue</strong>: App cannot reach the local server.</li><li><strong>Solution</strong>: Use <code>10.0.2.2</code> to access host machine localhost from emulator.</li></ul><h2 id="_4-port-forwarding" tabindex="-1">4. Port Forwarding <a class="header-anchor" href="#_4-port-forwarding" aria-label="Permalink to &quot;4. Port Forwarding&quot;">​</a></h2><p>The development server is running on port 3000, but the emulator can&#39;t reach it.</p><ul><li><strong>Solution</strong>: Use ADB port forwarding: <code>adb reverse tcp:3000 tcp:3000</code></li></ul><h2 id="_5-missing-component-registration" tabindex="-1">5. Missing Component Registration <a class="header-anchor" href="#_5-missing-component-registration" aria-label="Permalink to &quot;5. Missing Component Registration&quot;">​</a></h2><p>Forgot to call <code>navigator.registerBridgeComponent(...)</code>.</p><ul><li><strong>Issue</strong>: Web actions (like search) don&#39;t trigger native UI.</li><li><strong>Solution</strong>: Verify <code>MainActivity.kt</code> has all component registrations.</li></ul>',17)])])}const h=t(n,[["render",r]]);export{g as __pageData,h as default};
